<script setup lang="ts">/* LoopNode — 串联/并联循环器 */
import { computed } from 'vue';import { Handle, Position } from '@vue-flow/core';import { useCanvasStore } from '@/stores/canvasStore'
const p=defineProps<{id:string;data:any;selected?:boolean}>();const cs=useCanvasStore();const d=computed(()=>p.data||{})
const m=computed({get:()=>d.value.mode||'serial',set:v=>cs.updateNodeData(p.id,{mode:v})})
const k=computed({get:()=>d.value.loopKind||'image',set:v=>cs.updateNodeData(p.id,{loopKind:v})})
function run(){window.dispatchEvent(new CustomEvent('jc-canvas-run-node',{detail:p.id}))}</script>
<template><div class="x" :class="{sel:selected}" :style="{borderColor:selected?'#a78bfa':'var(--border)'}"><Handle type="target" :position="Position.Left" :style="{background:'#a78bfa',width:10,height:10,border:'none'}"/><div class="xh"><div class="xi" style="background:rgba(167,139,250,.18);color:#c4b5fd"><JcIcon name="repeat" style="font-size:13px" /></div><div class="xl">循环器</div><button class="xr" :disabled="data.status==='running'" @pointerdown.stop @click.stop="run"><JcIcon :name="data.status==='running'?'stop':'play_arrow'" /></button></div><div class="xb" @mousedown.stop><select v-model="m" class="xi2"><option value="serial">串联</option><option value="parallel">并联</option></select><select v-model="k" class="xi2"><option value="text">文本</option><option value="image">图像</option><option value="video">视频</option><option value="audio">音频</option></select><div v-if="data.totalCount" class="xs">{{data.currentIndex??0}}/{{data.totalCount}} · 失败 {{data.failCount??0}}</div><div v-if="data.status==='running'" class="xp">{{data.detail||'循环中'}}</div><div v-if="data.error" class="xe"><JcIcon name="error" style="font-size:11px" />{{data.error}}</div></div><Handle type="source" :position="Position.Right" :style="{background:'#a78bfa',width:10,height:10,border:'none'}"/></div></template>
<style scoped>.x{width:260px;border:2px solid var(--border);border-radius:12px;background:var(--paper);box-shadow:var(--jc-shadow-sm);color:var(--ink1)}.x.sel{border-color:#a78bfa}.xh{display:flex;align-items:center;gap:8px;padding:8px 12px;border-bottom:1px solid var(--border2)}.xi{width:24px;height:24px;border-radius:6px;display:flex;align-items:center;justify-content:center}.xl{flex:1;font-size:13px;font-weight:600}.xr{width:26px;height:26px;border:1px solid var(--border);border-radius:6px;background:var(--surface);color:var(--ink2);cursor:pointer;display:flex;align-items:center;justify-content:center}.xr:disabled{opacity:.4}.xb{padding:10px;display:flex;flex-direction:column;gap:6px}.xi2{width:100%;border:1px solid var(--border);border-radius:6px;background:var(--surface);color:var(--ink1);padding:5px 8px;font-size:11px;outline:none;font:inherit}.xs{font-size:11px;color:var(--ink2);padding:4px 6px;background:var(--surface);border-radius:4px}.xp{font-size:10px;color:var(--ink3)}.xe{display:flex;align-items:flex-start;gap:4px;font-size:10px;color:#f87171;background:rgba(239,68,68,.1);border:1px solid rgba(239,68,68,.2);border-radius:4px;padding:4px 8px}</style>
